local FontMapping = {
    ["SourceSans"] = TextFontPreset.SourceSans,
    ["PressStart2P"] = TextFontPreset.PressStart2P,
    ["Montserrat"] = TextFontPreset.Montserrat,
    ["RobotoMono"] = TextFontPreset.RobotoMono,
    ["Rubik"] = TextFontPreset.Rubik,
    ["Poppins"] = TextFontPreset.Poppins,
    ["Domine"] = TextFontPreset.Domine,
    ["Fredoka"] = TextFontPreset.Fredoka,
    ["ComicNeue"] = TextFontPreset.ComicNeue,
    ["Orbitron"] = TextFontPreset.Orbitron,
    ["Papyrus"] = TextFontPreset.Papyrus,
    ["ComicSansMS"] = TextFontPreset.ComicSansMS
}

local ValidSet = {}
for Char in ValidChars:gmatch("[^\128-\191][\128-\191]*") do
    ValidSet[Char] = true
end

local function GetFontName(Text3D)
    for Name, EnumValue in pairs(FontMapping) do
        if Text3D.Font == EnumValue then
            return Name
        end
    end
    return "SourceSans"
end

local function UTF8Chars(Str)
    return string.gmatch(Str, "[^\128-\191][\128-\191]*")
end

function Text3DScaler.FilterText(Text)
    local Result = {}
    for Char in UTF8Chars(Text) do
        if ValidSet[Char] or Char == "\n" then
            Result[#Result + 1] = Char
        end
    end
    return table.concat(Result)
end

function Text3DScaler.ValidateText(Text)
    for Char in UTF8Chars(Text) do
        if not (ValidSet[Char] or Char == "\n") then
            return false
        end
    end
    return true
end

function Text3DScaler.ScaleText(Text3D, MaxWidth, MaxHeight)
    local FontName = GetFontName(Text3D)
    local MonoWidth = FontData.Monospace[FontName]
    local CharWidths = FontData.Widths[FontName]
    local LineHeightRaw = FontData.Metrics[FontName] or 100

    local MaxRawWidth = 0
    local CurrentLineRawWidth = 0
    local TotalLines = 1

    for Char in UTF8Chars(Text3D.Text) do
        if Char == "\n" then
            if CurrentLineRawWidth > MaxRawWidth then
                MaxRawWidth = CurrentLineRawWidth
            end
            CurrentLineRawWidth = 0
            TotalLines = TotalLines + 1
        else
            CurrentLineRawWidth = CurrentLineRawWidth + (MonoWidth or CharWidths[Char] or CharWidths[DiacriticsMap[Char]] or 50)
        end
    end

    if CurrentLineRawWidth > MaxRawWidth then
        MaxRawWidth = CurrentLineRawWidth
    end

    local SizeFactor = Text3D.FontSize / 10
    local CurrentWidthStuds = (MaxRawWidth / 100) * SizeFactor
    local CurrentHeightStuds = ((LineHeightRaw * TotalLines) / 100) * SizeFactor

    CurrentWidthStuds = math.max(CurrentWidthStuds, 0.001)
    CurrentHeightStuds = math.max(CurrentHeightStuds, 0.001)

    local FinalScale = math.min(MaxWidth / CurrentWidthStuds, MaxHeight / CurrentHeightStuds)

    Text3D.Size = Vector3.New(FinalScale, FinalScale, 1)
end

function Text3DScaler.SetTextAndScale(Text3D, NewText, MaxWidth, MaxHeight)
    Text3D.Text = NewText
    Text3DScaler.ScaleText(Text3D, MaxWidth, MaxHeight)
end

return Text3DScaler
